// SignUp.js:
import React, { useState } from "react";
import { Form, Button } from "react-bootstrap";
import "../Style Css/SignUpForm.css";
import { Link } from "react-router-dom";
import axios from 'axios';
import { useNavigate } from 'react-router-dom';


function SignUp() {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const navigate = useNavigate();

  const handleSignUp = async (e) => {
        e.preventDefault(); // Page refresh hone se rokne ke liye

        try {
            
            const response = await axios.post('http://localhost:5000/register', {
                name: name,
                password: password
            });

            // 3. Agar response sahi aaya
            alert(response.data.message); // "Account kamyabi se ban gaya!"
            navigate('/Login'); // Login page par bhej dena

        } catch (error) {
            console.error("Signup Error:", error);
            alert("Signup fail ho gaya!");
        }
    };

  return (
    <div className="signup-page" onSubmit={handleSignUp}>
      <div className="signup-card">
        <h2 className="text-center mb-4 signup-title">Create Account</h2>
        <p className="text-center mb-4 text-muted">
          Join us to manage your tasks effortlessly
        </p>
        <Form onSubmit={handleSignUp}>
          <Form.Group className="mb-3" controlId="formBasicName">
            <Form.Label>Full Name</Form.Label>
            <Form.Control
              type="text"
              placeholder="Enter your name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              className="signup-input"
            />
          </Form.Group>
          <Form.Group className="mb-3" controlId="formBasicEmail">
            <Form.Label>Email address</Form.Label>
            <Form.Control
              type="email"
              placeholder="Enter email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              className="signup-input"
            />
          </Form.Group>

          <Form.Group className="mb-4" controlId="formBasicPassword">
            <Form.Label>Password</Form.Label>
            <Form.Control
              type="password"
              placeholder="Password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              className="signup-input"
            />
          </Form.Group>

          <Form.Group className="mb-4" controlId="formBasicConfirmPassword">
            <Form.Label>Confirm Password</Form.Label>
            <Form.Control
              type="password"
              placeholder="Confirm Password"
              value={confirmPassword}
              onChange={(e) => setConfirmPassword(e.target.value)}
              className="signup-input"
            />
          </Form.Group>
         
          <Button variant="primary" type="submit" className="w-100 signup-btn">
            Sign Up
          </Button>
         
          <p className="text-center mt-4 text-muted">
            Already have an account? <Link to="/login">Login</Link>
          </p>
        </Form>
      </div>
    </div>
  );
}

export default SignUp;
